import { Component, inject, signal, effect, ChangeDetectionStrategy } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router, RouterLink } from '@angular/router';

// Services
import { UserService } from '../../services/UserService';
import { TokenService } from '../../services/token.service';

// Angular Material Imports
import { MatButtonModule } from '@angular/material/button';
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';

// Define Interface
export interface UserProfile {
  id: string;
  username: string;
  avatarUrl: string | null;
  bio: string | null;
  following: boolean;
}

@Component({
  selector: 'app-users-page',
  standalone: true,
  imports: [CommonModule, RouterLink, MatButtonModule, MatProgressSpinnerModule],
  templateUrl: './users-page.html',
  styleUrls: ['./users-page.css'],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class UsersPageComponent {
  // --- INJECTIONS ---
  private userService = inject(UserService);
  private tokenService = inject(TokenService);
  private router = inject(Router);

  // --- STATE SIGNALS ---
  users = signal<UserProfile[]>([]);
  loading = signal(true);
  loadingMore = signal(false);
  isLastPage = signal(false);

  // Directly access Auth Signal
  currentUserId = this.tokenService.userId;

  // Constants
  readonly skeletonItems = new Array(8);
  private currentPage = 0;
  private readonly pageSize = 8;

  constructor() {
    // Declarative Load: Trigger initial load when component is created
    effect(() => {
      this.loadUsers();
    });
  }

  loadUsers() {
    const isFirstLoad = this.currentPage === 0;

    if (isFirstLoad) {
      this.loading.set(true);
    } else {
      this.loadingMore.set(true);
    }

    this.userService.getAllUsers(this.currentPage, this.pageSize).subscribe({
      next: (data) => {
        // Filter out myself
        const myId = this.currentUserId();
        console.log(data);
        const newUsers = data.content.filter((u: any) => u.id !== myId);

        if (isFirstLoad) {
          this.users.set(newUsers);
        } else {
          // Append
          this.users.update((current) => [...current, ...newUsers]);
        }

        // Pagination Check
        const totalPages = data.page.totalPages;
        const pageNum = data.page.number;
        // Last page if current page index equals last index OR no pages
        const isLast = totalPages === 0 || pageNum >= totalPages - 1;

        this.isLastPage.set(isLast);
        this.loading.set(false);
        this.loadingMore.set(false);
      },
      error: () => {
        this.loading.set(false);
        this.loadingMore.set(false);
      },
    });
  }

  loadMore() {
    if (!this.isLastPage() && !this.loadingMore()) {
      this.currentPage++;
      this.loadUsers();
    }
  }

  toggleFollow(user: UserProfile) {
    if (!this.tokenService.isAuthenticated()) {
      this.router.navigate(['/auth/login']);
      return;
    }

    // 1. Optimistic UI Update
    const newStatus = !user.following;
    this.updateFollowState(user.id, newStatus);

    // 2. API Call
    const action$ = user.following
      ? this.userService.unfollowUser(user.id)
      : this.userService.followUser(user.id);

    action$.subscribe({
      error: () => {
        // 3. Rollback on Error
        this.updateFollowState(user.id, !newStatus);
      },
    });
  }

  // Helper for immutable updates
  private updateFollowState(userId: string, newStatus: boolean) {
    this.users.update((list) =>
      list.map((u) => (u.id === userId ? { ...u, following: newStatus } : u))
    );
  }
}

import {
  Component,
  ElementRef,
  inject,
  OnDestroy,
  OnInit,
  ViewChild,
  ViewEncapsulation,
  signal,
} from '@angular/core';
import { ReactiveFormsModule, FormBuilder, Validators, FormControl } from '@angular/forms';
import { Router, RouterLink, ActivatedRoute } from '@angular/router';
import { CommonModule } from '@angular/common';
import { Observable, of, from } from 'rxjs';
import { concatMap, debounceTime, last, startWith, switchMap, tap } from 'rxjs/operators';
import { toSignal, takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { COMMA, ENTER } from '@angular/cdk/keycodes';

// TipTap Imports
import { TiptapEditorDirective } from 'ngx-tiptap';
import { Editor } from '@tiptap/core';
import StarterKit from '@tiptap/starter-kit';
import Placeholder from '@tiptap/extension-placeholder';
import { Markdown } from 'tiptap-markdown';
import Link from '@tiptap/extension-link';
import Image from '@tiptap/extension-image';

// Services
import { PostService } from '../../services/post.service';
import { ToastService } from '../../services/toast.service';

// Angular Material Imports
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { MatTooltipModule } from '@angular/material/tooltip';
import { MatProgressBarModule } from '@angular/material/progress-bar';
import { MatChipsModule, MatChipInputEvent } from '@angular/material/chips';
import { MatFormFieldModule } from '@angular/material/form-field';
import {
  MatAutocompleteModule,
  MatAutocompleteSelectedEvent,
  MatAutocompleteTrigger,
} from '@angular/material/autocomplete';

@Component({
  selector: 'app-add-post',
  standalone: true,
  imports: [
    ReactiveFormsModule,
    RouterLink,
    CommonModule,
    TiptapEditorDirective,
    MatButtonModule,
    MatIconModule,
    MatTooltipModule,
    MatProgressBarModule,
    MatChipsModule,
    MatFormFieldModule,
    MatAutocompleteModule,
  ],
  templateUrl: './add-post.html',
  styleUrls: ['./add-post.css'],
  encapsulation: ViewEncapsulation.None,
})
export class AddPost implements OnInit, OnDestroy {
  // Dependencies
  private fb = inject(FormBuilder);
  private postService = inject(PostService);
  private router = inject(Router);
  private route = inject(ActivatedRoute);
  private toast = inject(ToastService);

  private readonly BACKEND_URL = 'http://localhost:8080';

  // --- LIMITS ---
  private readonly MAX_TAGS = 5;
  private readonly MAX_TAG_LENGTH = 20;

  // --- 1. STATE SIGNALS ---
  isSubmitting = signal(false);
  uploadProgress = signal(0);
  errorMessage = signal('');
  editorMediaLoading = signal(false);

  // Tags State
  tags = signal<string[]>([]);

  // Edit Mode State
  isEditMode = signal(false);
  currentPostId = signal<string | null>(null);

  // Non-signal state
  editor!: Editor;
  existingMediaUrl: string | null = null;
  selectedFile: File | null = null;
  coverPreviewUrl: string | null = null;

  // --- 2. FORMS & AUTOCOMPLETE ---
  readonly separatorKeysCodes = [ENTER, COMMA] as const;
  tagCtrl = new FormControl('');

  filteredTags = toSignal(
    this.tagCtrl.valueChanges.pipe(
      startWith(null),
      debounceTime(300),
      switchMap((value: string | null) => {
        if (value && value.length > 0) {
          const cleanVal = value.replace('#', '').toLowerCase();
          return this.postService.searchTags(cleanVal);
        } else {
          return of([]);
        }
      })
    ),
    { initialValue: [] }
  );

  @ViewChild('tagInput') tagInput!: ElementRef<HTMLInputElement>;
  @ViewChild(MatAutocompleteTrigger) autocompleteTrigger!: MatAutocompleteTrigger;

  // Added strict Validators mapped to DTO requirements
  postForm = this.fb.group({
    title: ['', [Validators.required, Validators.minLength(3), Validators.maxLength(150)]],
    description: ['', [Validators.required, Validators.minLength(10), Validators.maxLength(50000)]], // description holds full body here
    mediaType: ['IMAGE'],
  });

  constructor() {
    // Safely subscribe to route params and ensure cleanup using takeUntilDestroyed
    this.route.paramMap
      .pipe(
        takeUntilDestroyed(),
        switchMap((params) => {
          const id = params.get('id');
          if (id) {
            this.isEditMode.set(true);
            this.currentPostId.set(id);
            return this.postService.getPostMetadata(id);
          }
          return of(null);
        })
      )
      .subscribe((post) => {
        if (post) {
          this.populateForm(post);
        }
      });
  }

  private populateForm(post: any) {
    this.postForm.patchValue({
      title: post.title,
      description: '',
      mediaType: post.mediaType,
    });

    if (post.tags) {
      const parsedTags = Array.from(post.tags as string[]);
      this.tags.set(parsedTags.slice(0, this.MAX_TAGS));
    }

    if (post.mediaUrl) {
      this.existingMediaUrl = post.mediaUrl;
      this.coverPreviewUrl = this.BACKEND_URL + post.mediaUrl;
    }

    this.loadDraftContent(post.id);
  }

  ngOnInit(): void {
    this.editor = new Editor({
      extensions: [
        StarterKit,
        Image.configure({ inline: false, allowBase64: false }),
        Markdown.configure({ html: true, transformPastedText: true, transformCopiedText: true }),
        Link.configure({ openOnClick: false, autolink: true }),
        Placeholder.configure({ placeholder: 'Tell your story...' }),
      ],
      editorProps: { attributes: { class: 'medium-editor-content' } },
      onUpdate: ({ editor }) => {
        const markdown = (editor.storage as any).markdown.getMarkdown();
        this.postForm.patchValue({ description: markdown });
      },
    });
  }

  ngOnDestroy(): void {
    if (this.editor) {
      this.editor.destroy();
    }
    if (this.coverPreviewUrl && this.coverPreviewUrl.startsWith('blob:')) {
      URL.revokeObjectURL(this.coverPreviewUrl);
    }
  }

  // --- 5. TAG LOGIC (With Limits) ---

  private normalizeTag(tag: string): string {
    return tag.replace(/#/g, '').trim().toLowerCase();
  }

  addTag(event: MatChipInputEvent): void {
    if (this.autocompleteTrigger.panelOpen) return;

    const value = (event.value || '').trim();
    const cleanValue = this.normalizeTag(value);

    this.processTagAddition(cleanValue);

    event.chipInput!.clear();
    this.tagCtrl.setValue(null);
  }

  selected(event: MatAutocompleteSelectedEvent): void {
    const rawValue = event.option.value;
    const cleanValue = this.normalizeTag(rawValue);

    this.processTagAddition(cleanValue);

    this.tagInput.nativeElement.value = '';
    this.tagCtrl.setValue(null);
  }

  private processTagAddition(cleanValue: string) {
    if (!cleanValue) return;

    if (cleanValue.length > this.MAX_TAG_LENGTH) {
      this.toast.show(`Tags cannot exceed ${this.MAX_TAG_LENGTH} characters.`, 'error');
      return;
    }

    this.tags.update((current) => {
      if (current.length >= this.MAX_TAGS) {
        this.toast.show(`You can only add up to ${this.MAX_TAGS} tags.`, 'error');
        return current;
      }
      if (!current.includes(cleanValue)) {
        return [...current, cleanValue];
      }
      return current;
    });
  }

  removeTag(tag: string): void {
    this.tags.update((current) => current.filter((t) => t !== tag));
  }

  // --- 6. ACTIONS ---

  loadDraftContent(id: string) {
    this.postService.getFullPostContent(id).subscribe((content) => {
      if (this.editor) {
        this.editor.commands.setContent(content);
        this.postForm.patchValue({ description: content });
      }
    });
  }

  get isVideoType(): boolean {
    return this.postForm.get('mediaType')?.value === 'VIDEO';
  }

  setLink() {
    const previousUrl = this.editor.getAttributes('link')['href'];
    const url = window.prompt('URL', previousUrl);
    if (url === null) return;
    if (url === '') {
      this.editor.chain().focus().extendMarkRange('link').unsetLink().run();
      return;
    }
    this.editor.chain().focus().extendMarkRange('link').setLink({ href: url }).run();
  }

  triggerEditorImageInput() {
    document.getElementById('editor-image-upload')?.click();
  }

  onEditorFileSelected(event: Event) {
    const input = event.target as HTMLInputElement;
    if (input.files && input.files[0]) {
      this.uploadEditorMedia(input.files[0]);
      input.value = '';
    }
  }

  uploadEditorMedia(file: File) {
    this.editorMediaLoading.set(true);
    this.postService.uploadEditorMedia(file).subscribe({
      next: (res) => {
        this.editorMediaLoading.set(false);
        const fullUrl = `${this.BACKEND_URL}${res.url}`;
        this.editor.chain().focus().setImage({ src: fullUrl }).run();
      },
      error: () => {
        this.editorMediaLoading.set(false);
        this.toast.show('Failed to upload image.', 'error');
      },
    });
  }

  triggerFileInput() {
    document.getElementById('cover-upload')?.click();
  }

  onFileSelected(event: Event) {
    const input = event.target as HTMLInputElement;
    if (input.files && input.files[0]) {
      this.selectedFile = input.files[0];
      const fileType = this.selectedFile.type;

      if (fileType.startsWith('video/')) {
        this.postForm.patchValue({ mediaType: 'VIDEO' });
        this.coverPreviewUrl = URL.createObjectURL(this.selectedFile);
      } else {
        this.postForm.patchValue({ mediaType: 'IMAGE' });
        const reader = new FileReader();
        reader.onload = (e) => (this.coverPreviewUrl = e.target?.result as string);
        reader.readAsDataURL(this.selectedFile);
      }
    }
  }

  removeCover() {
    this.selectedFile = null;
    this.coverPreviewUrl = null;
    this.existingMediaUrl = null;
    this.postForm.patchValue({ mediaType: 'IMAGE' });
    const input = document.getElementById('cover-upload') as HTMLInputElement;
    if (input) input.value = '';
  }

  autoResize(event: Event) {
    const el = event.target as HTMLTextAreaElement;
    el.style.height = 'auto';
    el.style.height = el.scrollHeight + 'px';
  }

  // --- 7. SAVE / PUBLISH LOGIC ---

  onPublish() {
    this.handleSave(true);
  }
  onSaveDraft() {
    this.handleSave(false);
  }

  private handleSave(publish: boolean) {
    // Validate Form
    if (this.postForm.invalid) {
      if (this.postForm.get('title')?.hasError('maxlength')) {
        this.toast.show('Title is too long (max 150 characters).', 'error');
      } else if (this.postForm.get('description')?.hasError('maxlength')) {
        this.toast.show('Content is too long. Please reduce text.', 'error');
      } else {
        this.toast.show('Please provide a valid title and content.', 'error');
      }
      return;
    }

    if (this.editor.isEmpty) {
      this.toast.show('Please add some content to your story.', 'error');
      return;
    }

    this.isSubmitting.set(true);
    this.errorMessage.set('');
    this.uploadProgress.set(0);

    const fullContent = this.postForm.get('description')?.value || '';
    // Description in DTO expects a summary. Limit this to 150 to be safe for typical DB limits
    const summary = fullContent.substring(0, 150) + '...';
    const title = this.postForm.get('title')?.value;
    const currentMediaType = this.postForm.get('mediaType')?.value;

    let saveObservable: Observable<any>;
    const currentId = this.currentPostId();

    if (this.isEditMode() && currentId) {
      // --- Update ---
      const updatePayload: any = {
        title: title,
        description: summary,
        mediaType: currentMediaType,
        mediaUrl: this.existingMediaUrl,
        tags: this.tags(),
      };

      let preUpdateAction: Observable<any> = of(null);

      if (this.selectedFile) {
        preUpdateAction = this.postService.uploadEditorMedia(this.selectedFile).pipe(
          tap((res) => {
            updatePayload.mediaUrl = res.url;
            this.existingMediaUrl = res.url;
          })
        );
      }

      saveObservable = preUpdateAction.pipe(
        concatMap(() => this.postService.updatePost(currentId, updatePayload)),
        concatMap(() => this.postService.clearPostContent(currentId))
      );
    } else {
      // --- Init ---
      const formData = new FormData();
      formData.append('title', title || '');
      formData.append('description', summary);
      formData.append('mediaType', currentMediaType || 'IMAGE');

      this.tags().forEach((tag) => {
        formData.append('tags', tag);
      });

      if (this.selectedFile) {
        formData.append('media', this.selectedFile);
      }

      saveObservable = this.postService.initPost(formData).pipe(
        tap((res: any) => {
          this.currentPostId.set(res.id);
          if (res.mediaUrl) {
            this.existingMediaUrl = res.mediaUrl;
          }
        })
      );
    }

    saveObservable
      .pipe(
        concatMap(() => this.uploadChunksSequentially(this.currentPostId()!, fullContent)),
        concatMap(() => {
          if (publish) {
            const totalChunks = Math.ceil(fullContent.length / 4000);
            return this.postService.publishPost(this.currentPostId()!, totalChunks);
          }
          return of(null);
        })
      )
      .subscribe({
        next: () => {
          this.isSubmitting.set(false);
          if (publish) {
            this.toast.show('Story published successfully!', 'success');
            this.router.navigate(['/home']);
          } else {
            this.isEditMode.set(true);
            this.selectedFile = null;
            this.toast.show('Draft saved successfully', 'success');
          }
        },
        error: (err) => {
          console.error(err);
          this.toast.show('Could not save story.', 'error');
          this.isSubmitting.set(false);
        },
      });
  }

  private uploadChunksSequentially(postId: string, content: string): Observable<any> {
    const CHUNK_SIZE = 4000;
    const totalChunks = Math.ceil(content.length / CHUNK_SIZE);
    const chunks: { index: number; content: string }[] = [];

    for (let i = 0; i < totalChunks; i++) {
      const start = i * CHUNK_SIZE;
      const end = Math.min(start + CHUNK_SIZE, content.length);
      chunks.push({ index: i, content: content.substring(start, end) });
    }

    if (chunks.length === 0) return of(null);

    return from(chunks).pipe(
      concatMap((chunk, i) => {
        this.uploadProgress.set(Math.round(((i + 1) / totalChunks) * 100));
        return this.postService.uploadChunk(postId, chunk.index, chunk.content);
      }),
      last()
    );
  }
}

import {
  Component,
  OnInit,
  AfterViewInit,
  inject,
  ViewChildren,
  QueryList,
  HostListener,
  signal,
  effect,
  DestroyRef,
  ChangeDetectionStrategy,
} from '@angular/core';
import { CommonModule, TitleCasePipe, DatePipe } from '@angular/common';
import { RouterLink } from '@angular/router';
import { AdminService, DashboardStats } from '../../../services/admin.service';
import { ChartConfiguration, ChartOptions } from 'chart.js';
import { BaseChartDirective } from 'ng2-charts';

// Angular Material Imports
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { MatTableModule } from '@angular/material/table';
import { MatTooltipModule } from '@angular/material/tooltip';
import { MatProgressSpinnerModule } from '@angular/material/progress-spinner';

@Component({
  selector: 'app-admin-dashboard',
  standalone: true,
  imports: [
    CommonModule,
    RouterLink,
    BaseChartDirective,
    MatButtonModule,
    MatIconModule,
    MatTableModule,
    MatTooltipModule,
    MatProgressSpinnerModule,
    TitleCasePipe,
    DatePipe,
  ],
  templateUrl: './dashboard.html',
  styleUrls: ['./dashboard.css'],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class AdminDashboardComponent implements OnInit, AfterViewInit {
  private adminService = inject(AdminService);
  private destroyRef = inject(DestroyRef); // Clean up observers

  // ViewChildren allows us to access the charts to manually update them
  @ViewChildren(BaseChartDirective) charts!: QueryList<BaseChartDirective>;

  // --- 1. STATE SIGNALS ---
  activeTab = signal<'overview' | 'users' | 'posts' | 'reports'>('overview');
  stats = signal<DashboardStats | null>(null);
  message = signal<string>('');
  isLoading = signal(false);

  // Data Lists
  users = signal<any[]>([]);
  posts = signal<any[]>([]);
  reports = signal<any[]>([]);

  // Pagination State
  // We group this to keep the namespace clean
  pagination = signal({
    users: { page: 0, size: 20, loading: false, finished: false },
    posts: { page: 0, size: 20, loading: false, finished: false },
    reports: { page: 0, size: 20, loading: false, finished: false },
  });

  // Material Table Columns
  userColumns: string[] = ['user', 'role', 'status', 'actions'];
  postColumns: string[] = ['title', 'author', 'date', 'actions'];
  reportColumns: string[] = ['details', 'status', 'actions'];

  // --- 2. CHART CONFIGURATION ---
  // Initial empty data structures
  public lineChartData: ChartConfiguration<'line'>['data'] = { labels: [], datasets: [] };
  public postChartData: ChartConfiguration<'bar'>['data'] = { labels: [], datasets: [] };

  public lineChartOptions: ChartOptions<'line'> = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: { display: false },
      tooltip: { padding: 10, cornerRadius: 4, displayColors: false },
    },
    scales: {
      x: { grid: { display: false } },
      y: { grid: { display: true } },
    },
  };

  public barChartOptions: ChartOptions<'bar'> = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: { legend: { display: false } },
    scales: {
      x: { grid: { display: false } },
      y: { grid: { display: true } },
    },
  };

  private themeObserver: MutationObserver | null = null;

  constructor() {
    // EFFECT: Update charts when stats data arrives
    effect(() => {
      const currentStats = this.stats();
      if (currentStats) {
        this.setupCharts(currentStats);
      }
    });
  }

  ngOnInit() {
    this.loadStats();
  }

  ngAfterViewInit() {
    // Theme switching logic requires DOM observation
    this.themeObserver = new MutationObserver(() => this.updateChartTheme());
    this.themeObserver.observe(document.body, { attributes: true, attributeFilter: ['class'] });

    // Run once to set initial theme colors
    setTimeout(() => this.updateChartTheme(), 100);

    // Register cleanup
    this.destroyRef.onDestroy(() => {
      this.themeObserver?.disconnect();
    });
  }

  // === 3. EVENT LISTENERS ===

  @HostListener('window:scroll', [])
  onWindowScroll() {
    // Only load more if not on overview tab
    if (this.activeTab() === 'overview') return;

    const pos =
      (document.documentElement.scrollTop || document.body.scrollTop) + window.innerHeight;
    const max = document.documentElement.scrollHeight || document.body.scrollHeight;

    // Load more when user scrolls to bottom (buffer of 100px)
    if (pos > max - 100) {
      const tab = this.activeTab();
      if (tab === 'users') this.loadUsers();
      if (tab === 'posts') this.loadPosts();
      if (tab === 'reports') this.loadReports();
    }
  }

  switchTab(tab: 'overview' | 'users' | 'posts' | 'reports') {
    this.activeTab.set(tab);
    this.message.set('');

    if (tab === 'overview') {
      this.loadStats();
      // Re-apply theme after a short delay to allow canvas to render
      setTimeout(() => this.updateChartTheme(), 100);
    }

    // Lazy load data if empty
    if (tab === 'users' && this.users().length === 0) this.loadUsers();
    if (tab === 'posts' && this.posts().length === 0) this.loadPosts();
    if (tab === 'reports' && this.reports().length === 0) this.loadReports();
  }

  // === 4. DATA LOADING ===

  loadStats() {
    this.isLoading.set(true);
    this.adminService.getDashboardStats().subscribe({
      next: (res) => {
        this.stats.set(res);
        this.isLoading.set(false);
      },
      error: (err) => {
        console.error('Stats Error', err);
        this.isLoading.set(false);
      },
    });
  }

  setupCharts(stats: DashboardStats) {
    // Map data from API to Chart.js format
    const userLabels = stats.userGrowth.map((d) => d.label);
    const userValues = stats.userGrowth.map((d) => d.value);

    this.lineChartData = {
      labels: userLabels,
      datasets: [
        {
          data: userValues,
          label: 'Users',
          fill: true,
          tension: 0.4,
          borderColor: '#1a8917',
          backgroundColor: 'rgba(26, 137, 23, 0.1)',
          pointBackgroundColor: '#1a8917',
          pointBorderColor: '#ffffff',
        },
      ],
    };

    const postLabels = stats.postGrowth.map((d) => d.label);
    const postValues = stats.postGrowth.map((d) => d.value);

    this.postChartData = {
      labels: postLabels,
      datasets: [
        {
          data: postValues,
          label: 'Stories',
          backgroundColor: '#3b82f6',
          borderRadius: 4,
        },
      ],
    };

    // Trigger update on directives
    this.charts?.forEach((c) => c.chart?.update());
  }

  updateChartTheme() {
    if (!this.charts) return;

    // Read CSS Variables to make charts match Dark/Light mode
    const styles = getComputedStyle(document.body);
    const textPrimary = styles.getPropertyValue('--text-primary').trim();
    const textSecondary = styles.getPropertyValue('--text-secondary').trim();
    const borderColor = styles.getPropertyValue('--border').trim();
    const cardBg = styles.getPropertyValue('--card').trim();

    const scaleOptions = {
      x: { grid: { display: false, color: borderColor }, ticks: { color: textSecondary } },
      y: { grid: { color: borderColor }, ticks: { color: textSecondary } },
    };

    const pluginOptions = {
      legend: { display: false },
      tooltip: { backgroundColor: textPrimary, titleColor: cardBg, bodyColor: cardBg },
    };

    // Apply to options
    this.lineChartOptions = {
      ...this.lineChartOptions,
      scales: scaleOptions,
      plugins: pluginOptions,
    };
    this.barChartOptions = {
      ...this.barChartOptions,
      scales: scaleOptions,
      plugins: pluginOptions,
    };

    this.charts.forEach((chart) => chart.chart?.update());
  }

  // === 5. PAGINATED DATA LOGIC ===

  loadUsers() {
    const pag = this.pagination();
    if (pag.users.loading || pag.users.finished) return;

    // Set Loading State
    this.pagination.update((p) => ({ ...p, users: { ...p.users, loading: true } }));

    this.adminService.getAllUsers(pag.users.page, pag.users.size).subscribe({
      next: (res) => {
        // Append new data
        this.users.update((current) => [...current, ...res.content]);

        // Update pagination cursor
        this.pagination.update((p) => ({
          ...p,
          users: {
            ...p.users,
            loading: false,
            page: p.users.page + 1,
            finished: res.page.number >= res.page.totalPages - 1,
          },
        }));
      },
      error: () => {
        this.pagination.update((p) => ({ ...p, users: { ...p.users, loading: false } }));
      },
    });
  }

  loadPosts() {
    const pag = this.pagination();
    if (pag.posts.loading || pag.posts.finished) return;

    this.pagination.update((p) => ({ ...p, posts: { ...p.posts, loading: true } }));

    this.adminService.getAllPosts(pag.posts.page, pag.posts.size).subscribe({
      next: (res) => {
        this.posts.update((current) => [...current, ...res.content]);

        this.pagination.update((p) => ({
          ...p,
          posts: {
            ...p.posts,
            loading: false,
            page: p.posts.page + 1,
            finished: res.page.number >= res.page.totalPages - 1,
          },
        }));
      },
      error: () => {
        this.pagination.update((p) => ({ ...p, posts: { ...p.posts, loading: false } }));
      },
    });
  }

  loadReports() {
    const pag = this.pagination();
    if (pag.reports.loading) return; // Simple loading check (assuming reports are 1 page for now)

    this.isLoading.set(true);
    this.adminService.getAllReports().subscribe({
      next: (res: any) => {
        // Handle varying API responses (Page vs List)
        const data =
          res.content && Array.isArray(res.content) ? res.content : Array.isArray(res) ? res : [];
        this.reports.set(data);
        this.isLoading.set(false);
      },
      error: () => this.isLoading.set(false),
    });
  }

  // === 6. ACTIONS (OPTIMISTIC UPDATES) ===

  banUser(id: string) {
    if (!confirm('Are you sure?')) return;

    this.adminService.banUser(id).subscribe({
      next: (msg) => {
        this.message.set(msg);
        // Optimistic update of local array
        this.users.update((list) =>
          list.map((u) => (u.id === id ? { ...u, banned: !u.banned } : u))
        );
      },
      error: (err) => console.error(err),
    });
  }

  deleteUser(id: string) {
    if (!confirm('Delete user?')) return;

    this.adminService.deleteUser(id).subscribe({
      next: (msg) => {
        this.message.set(msg);
        this.users.update((list) => list.filter((u) => u.id !== id));
      },
      error: (err) => console.error(err),
    });
  }

  resolveReport(id: string) {
    this.adminService.resolveReport(id).subscribe({
      next: (msg) => {
        this.message.set(msg);
        this.reports.update((list) =>
          list.map((r) => (r.id === id ? { ...r, resolved: true } : r))
        );
      },
      error: (err) => console.error(err),
    });
  }

  toggleRole(user: any) {
    const newRole = user.role === 'ADMIN' ? 'USER' : 'ADMIN';
    const action = user.role === 'ADMIN' ? 'Demote' : 'Promote';

    if (!confirm(`Are you sure you want to ${action} ${user.username} to ${newRole}?`)) return;

    this.adminService.updateUserRole(user.id, newRole).subscribe({
      next: (msg) => {
        this.message.set(msg);
        this.users.update((list) =>
          list.map((u) => (u.id === user.id ? { ...u, role: newRole } : u))
        );
      },
      error: () => this.message.set('Failed to update role'),
    });
  }
}

import { Component, inject, OnInit, signal, ChangeDetectionStrategy } from '@angular/core';
import { CommonModule } from '@angular/common'; // DatePipe, UpperCasePipe
import { ActivatedRoute, Router, RouterLink } from '@angular/router';

// Services & Models
import { PostService } from '../../services/post.service';
import { TokenService } from '../../services/token.service';
import { PostResponse } from '../../models/POST/PostResponse';
import { Page } from '../../models/Page';

// Components
import { PostOptionsMenuComponent } from '../../share/PostOptionsMenu/post-options-menu';
import { ConfirmDialogComponent } from '../../share/ConfirmDialogComponent/confirm-dialog';
import { SuggestedUsersComponent } from '../../share/SuggestedAccounts/suggested-users';
import { PopularTagsComponent } from '../../share/popular-tags/popular-tags';

// Angular Material Imports
import { MatDialog, MatDialogModule } from '@angular/material/dialog';
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { MatTooltipModule } from '@angular/material/tooltip';

@Component({
  selector: 'app-home',
  standalone: true,
  imports: [
    CommonModule,
    RouterLink,
    PostOptionsMenuComponent,
    SuggestedUsersComponent,
    PopularTagsComponent,
    MatDialogModule,
    MatButtonModule,
    MatIconModule,
    MatTooltipModule,
  ],
  templateUrl: './home.html',
  styleUrl: './home.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class Home implements OnInit {
  // --- INJECTIONS ---
  private postService = inject(PostService);
  private tokenService = inject(TokenService);
  private router = inject(Router);
  private dialog = inject(MatDialog);
  private route = inject(ActivatedRoute);

  // --- 1. STATE SIGNALS ---
  posts = signal<PostResponse[]>([]);
  loading = signal(true);
  loadingMore = signal(false);
  hasMorePosts = signal(true);

  // Filter state
  selectedTag = signal<string | null>(null);

  // --- 2. COMPUTED / DERIVED STATE ---
  // We reference TokenService signals directly for reactivity
  isAdmin = this.tokenService.isAdminSignal;
  currentUserId = this.tokenService.userId;

  // Constants
  readonly skeletonItems = new Array(5);
  private currentPage = 0;
  private readonly pageSize = 4;

  ngOnInit(): void {
    // Listen to Query Params (e.g., ?tag=Java)
    this.route.queryParams.subscribe((params) => {
      const tag = params['tag'];
      this.resetFeed(tag);
    });
  }

  private resetFeed(tag: string | undefined) {
    this.posts.set([]);
    this.currentPage = 0;
    this.hasMorePosts.set(true);
    this.loading.set(true);

    if (tag) {
      this.selectedTag.set(tag);
      this.loadPostsByTag(tag);
    } else {
      this.selectedTag.set(null);
      this.loadAllPosts();
    }
  }

  // --- DATA LOADING ---

  private loadPostsByTag(tag: string) {
    this.postService.getPostsByTag(tag, this.currentPage, this.pageSize).subscribe({
      next: (data) => this.handleResponse(data),
      error: (err) => this.handleError(err),
    });
  }

  private loadAllPosts() {
    this.postService.getAllPosts(this.currentPage, this.pageSize).subscribe({
      next: (data) => this.handleResponse(data),
      error: (err) => this.handleError(err),
    });
  }

  private handleResponse(data: Page<PostResponse>) {
    if (this.currentPage === 0) {
      this.posts.set(data.content);
    } else {
      this.posts.update((current) => [...current, ...data.content]);
    }

    this.hasMorePosts.set(data.page.number < data.page.totalPages - 1);
    this.loading.set(false);
    this.loadingMore.set(false);
  }

  private handleError(err: any) {
    console.error(err);
    this.loading.set(false);
    this.loadingMore.set(false);
  }

  // --- ACTIONS ---

  loadMore() {
    if (this.loadingMore() || !this.hasMorePosts()) return;

    this.loadingMore.set(true);
    this.currentPage++;

    const tag = this.selectedTag();
    if (tag) {
      this.loadPostsByTag(tag);
    } else {
      this.loadAllPosts();
    }
  }

  toggleSave(event: Event, post: PostResponse) {
    event.stopPropagation();

    // 1. Optimistic UI Update
    const newState = !post.savedByCurrentUser;
    this.updatePostInList(post.id, { savedByCurrentUser: newState });

    // 2. API Call
    this.postService.toggleSavePost(post.id).subscribe({
      next: (res) => {
        // Confirm server state matches
        if (res.isSaved !== newState) {
          this.updatePostInList(post.id, { savedByCurrentUser: res.isSaved });
        }
      },
      error: () => {
        // 3. Rollback on error
        this.updatePostInList(post.id, { savedByCurrentUser: !newState });
      },
    });
  }

  clearFilter() {
    this.router.navigate(['/home']);
  }

  onReport(userId: string) {
    this.router.navigate(['/report', userId]); // Assuming route is /report/:userId
  }

  onDelete(p: PostResponse) {
    const dialogRef = this.dialog.open(ConfirmDialogComponent, {
      width: '380px',
      data: { message: 'Delete this story forever?' },
      panelClass: 'custom-dialog-panel',
      backdropClass: 'custom-backdrop-blur',
    });

    dialogRef.afterClosed().subscribe((result) => {
      if (result === true) {
        this.confirmDelete(p.id);
      }
    });
  }

  private confirmDelete(postId: string) {
    this.postService.deletePost(postId).subscribe({
      next: () => {
        // Immutable removal
        this.posts.update((current) => current.filter((p) => p.id !== postId));
      },
      error: (err) => console.error('Delete failed:', err),
    });
  }

  // Helper for immutable updates
  private updatePostInList(postId: string, changes: Partial<PostResponse>) {
    this.posts.update((current) =>
      current.map((p) => (p.id === postId ? { ...p, ...changes } : p))
    );
  }
}

