import { Component, inject, OnInit, signal, DestroyRef } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { RouterModule } from '@angular/router';
import { takeUntilDestroyed } from '@angular/core/rxjs-interop';
import { Subject, debounceTime, distinctUntilChanged } from 'rxjs';

import { PostService } from '../../services/post.service';
import { UserService } from '../../services/UserService';
import { TokenService } from '../../services/token.service';
import { PostResponse } from '../../models/POST/PostResponse';

import { MatIconModule } from '@angular/material/icon';
import { MatButtonModule } from '@angular/material/button';
import { MatChipsModule } from '@angular/material/chips';
import { MatCheckboxModule } from '@angular/material/checkbox';

@Component({
  selector: 'app-search',
  standalone: true,
  imports: [
    CommonModule,
    FormsModule,
    RouterModule,
    MatIconModule,
    MatButtonModule,
    MatChipsModule,
    MatCheckboxModule,
  ],
  templateUrl: './search.component.html',
  styleUrls: ['./search.component.css'],
})
export class SearchComponent implements OnInit {
  private postService = inject(PostService);
  private userService = inject(UserService);
  public tokenService = inject(TokenService);
  private destroyRef = inject(DestroyRef);

  // --- UI STATE SIGNALS ---
  activeTab = signal<'posts' | 'users'>('posts');
  loading = signal(false);
  loadingMore = signal(false);

  // --- SEARCH & FILTER SIGNALS ---
  searchQuery = signal<string>('');
  filterLiked = signal<boolean>(false);
  filterFollowed = signal<boolean>(false);

  // --- DATA SIGNALS ---
  posts = signal<PostResponse[]>([]);
  users = signal<any[]>([]);

  // --- PAGINATION ---
  page = 0;
  hasMore = signal(false);
  private readonly SIZE = 10;

  // RxJS Subject for debouncing user typing
  private searchSubject = new Subject<string>();

  ngOnInit() {
    // Listen to typing, wait 400ms, then trigger search
    this.searchSubject
      .pipe(debounceTime(400), distinctUntilChanged(), takeUntilDestroyed(this.destroyRef))
      .subscribe(() => {
        this.resetAndSearch();
      });

    // Initial load
    this.resetAndSearch();
  }

  // Called when user types in the input
  onSearchInput(event: Event) {
    const value = (event.target as HTMLInputElement).value;
    this.searchQuery.set(value);
    this.searchSubject.next(value);
  }

  // Switch tabs (Posts/Users)
  setTab(tab: 'posts' | 'users') {
    this.activeTab.set(tab);
    this.resetAndSearch();
  }

  // Toggle Filters (Posts only)
  toggleFilter(filter: 'liked' | 'followed') {
    if (filter === 'liked') this.filterLiked.set(!this.filterLiked());
    if (filter === 'followed') this.filterFollowed.set(!this.filterFollowed());
    this.resetAndSearch();
  }

  private resetAndSearch() {
    this.page = 0;
    this.posts.set([]);
    this.users.set([]);
    this.hasMore.set(false);
    this.executeSearch();
  }

  executeSearch() {
    this.loading.set(true);

    if (this.activeTab() === 'posts') {
      this.postService
        .searchPosts(
          this.searchQuery(),
          undefined, // author
          undefined, // tags array
          this.filterLiked(),
          this.filterFollowed(),
          this.page,
          this.SIZE
        )
        .subscribe({
          next: (res) => {
            if (this.page === 0) this.posts.set(res.content);
            else this.posts.update((prev) => [...prev, ...res.content]);

            this.hasMore.set(res.page.number < res.page.totalPages - 1);
            this.loading.set(false);
            this.loadingMore.set(false);
          },
          error: () => this.loading.set(false),
        });
    } else {
      this.userService.searchUsers(this.searchQuery(), this.page, this.SIZE).subscribe({
        next: (res) => {
          if (this.page === 0) this.users.set(res.content);
          else this.users.update((prev) => [...prev, ...res.content]);

          this.hasMore.set(res.page.number < res.page.totalPages - 1);
          this.loading.set(false);
          this.loadingMore.set(false);
        },
        error: () => this.loading.set(false),
      });
    }
  }

  loadMore() {
    if (!this.hasMore() || this.loadingMore()) return;
    this.loadingMore.set(true);
    this.page++;
    this.executeSearch();
  }
}

import { Component, inject, OnInit, signal, ChangeDetectionStrategy } from '@angular/core';
import { FormBuilder, ReactiveFormsModule, Validators, FormControl } from '@angular/forms';
import { ActivatedRoute, Router, RouterModule } from '@angular/router';
import { CommonModule } from '@angular/common';
import { UserService } from '../../services/UserService';
import { UserResponse } from '../../models/USER/UserResponse';
import { ToastService } from '../../services/toast.service';

// Angular Material Imports
import { MatFormFieldModule } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { MatButtonModule } from '@angular/material/button';
import { MatIconModule } from '@angular/material/icon';
import { switchMap } from 'rxjs';

@Component({
  selector: 'app-updateprofile',
  standalone: true,
  imports: [
    ReactiveFormsModule,
    RouterModule,
    CommonModule,
    MatFormFieldModule,
    MatInputModule,
    MatButtonModule,
    MatIconModule,
  ],
  templateUrl: './updateProfile.html',
  styleUrl: './updateProfile.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class UpdateProfile implements OnInit {
  // Services
  private userService = inject(UserService);
  private toastService = inject(ToastService);
  private fb = inject(FormBuilder);
  private router = inject(Router);
  private route = inject(ActivatedRoute);

  // State Signals
  user = signal<UserResponse | null>(null);
  avatarPreview = signal<string | ArrayBuffer | null>(null);
  fileError = signal<string | null>(null);
  isSubmitting = signal(false);

  // Internal
  private userId = '';
  private selectedFile: File | null = null;

  // Name Regex: Allows letters (including accents), spaces, hyphens, and apostrophes.
  private namePattern = /^[a-zA-ZÀ-ÿ\s\-']+$/;

  // Typed Form
  publicInfoForm = this.fb.group({
    bio: new FormControl('', [Validators.maxLength(500)]),
    firstname: new FormControl('', [
      Validators.required,
      Validators.minLength(2),
      Validators.maxLength(50),
      Validators.pattern(this.namePattern),
    ]),
    lastname: new FormControl('', [
      Validators.required,
      Validators.minLength(2),
      Validators.maxLength(50),
      Validators.pattern(this.namePattern),
    ]),
    username: new FormControl('', [
      Validators.required,
      Validators.minLength(3),
      Validators.maxLength(20),
      Validators.pattern(/^[a-zA-Z0-9._-]+$/),
    ]),
    email: new FormControl('', [Validators.required, Validators.email]),
    // Password fields are optional
    oldpassword: new FormControl(''),
    password: new FormControl('', [Validators.minLength(6)]),
  });

  ngOnInit(): void {
    // Handle route params reactively
    this.route.paramMap
      .pipe(
        switchMap((params) => {
          this.userId = params.get('id') || '';
          if (!this.userId) throw new Error('User ID missing');
          return this.userService.getUserFullData(this.userId);
        })
      )
      .subscribe({
        next: (data) => {
          this.user.set(data);

          // Initial Avatar
          if (data.avatarUrl) {
            this.avatarPreview.set('http://localhost:8080' + data.avatarUrl);
          }

          // Pre-fill form
          this.publicInfoForm.patchValue({
            firstname: data.firstname,
            lastname: data.lastname,
            username: data.username,
            email: data.email,
            bio: data.bio || '',
          });
        },
        error: (err) => {
          console.error(err);
          this.toastService.show('Failed to load profile data', 'error');
          this.router.navigate(['/home']);
        },
      });
  }

  onFileSelected(event: Event) {
    const input = event.target as HTMLInputElement;
    if (!input.files || input.files.length === 0) return;

    const file = input.files[0];

    // Validation
    if (!file.type.startsWith('image/')) {
      this.fileError.set('Only images are allowed.');
      return;
    }
    if (file.size > 20 * 1024 * 1024) {
      this.fileError.set('File is too large. Max 20MB.');
      return;
    }

    this.fileError.set(null);
    this.selectedFile = file;

    // Preview
    const reader = new FileReader();
    reader.onload = () => {
      this.avatarPreview.set(reader.result);
    };
    reader.readAsDataURL(file);

    // Mark form as dirty so Save button enables
    this.publicInfoForm.markAsDirty();
  }

  onSubmit() {
    if (this.publicInfoForm.invalid) return;

    this.isSubmitting.set(true);

    const formData = new FormData();
    const formVal = this.publicInfoForm.getRawValue();

    // Helper to append valid values
    const appendIf = (key: string, val: string | null | undefined) => {
      if (val !== null && val !== undefined && val !== '') formData.append(key, val);
    };

    appendIf('bio', formVal.bio);
    appendIf('firstname', formVal.firstname);
    appendIf('lastname', formVal.lastname);
    appendIf('username', formVal.username);
    appendIf('email', formVal.email);
    appendIf('oldpassword', formVal.oldpassword);
    appendIf('password', formVal.password);

    if (this.selectedFile) {
      formData.append('avatar', this.selectedFile, this.selectedFile.name);
    }

    this.userService.patchUser(formData, this.userId).subscribe({
      next: (res) => {
        this.isSubmitting.set(false);
        this.toastService.show('Profile updated successfully!', 'success');
        this.router.navigate(['/home']);
      },
      error: (err) => {
        this.isSubmitting.set(false);
        const msg = err.error?.error || 'Update failed. Please try again.';
        this.toastService.show(msg, 'error');
        console.error('Update Error:', err);
      },
    });
  }
}

import { Injectable, signal } from '@angular/core';
import { HttpClient, HttpParams } from '@angular/common/http';
import { Observable, tap } from 'rxjs';
import { UserPublicProfileDTO } from '../models/USER/UserPublicProfileDTO';
